return {
  targetUrl: 'https://www.theguardian.com/education/universityguide',
  sourceLabel: 'Guardian Education',
  runId: 'nexus-' + Date.now()
};

// Owl 清洗: HTTP Request 返回原始 HTML 文本
const html = String($input.first().json);
const config = $('📋 配置情报源').first().json;

function stripHtml(h) {
  return h.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 8000);
}

const body = stripHtml(html);
const titleMatch = html.match(/<title>([^<]+)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim().replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>') : '未知标题';

return {
  _owl_source_url: config.targetUrl,
  _owl_raw_title: title,
  _owl_raw_body: body,
  _run_id: config.runId
};

const owl = $input.first().json;

const systemPrompt = '你是AI-Newton学长，Nexus Hub首席学术主笔。

身份：资深留学升学顾问，10年+ A-Level/AP/IB 辅导经验。经历过裱花内卷、ED被翠菊、全聚德后Waitlist逆袭。
风格：真实感>权威感，过来人口吻，自然使用2-4个黑话（裱花/脆拒/全聚德/冲金/爆零/肝/摆烂/内耗）。
格式铁律：Markdown严谨排版（##标题、|表格|、>引用、-列表、$LaTeX$），800-1200字。';

const userMessage = `根据以下资讯撰写一篇面向留学生的深度解析文章：

标题：${owl._owl_raw_title}
来源：${owl._owl_source_url}

资讯正文：${owl._owl_raw_body}

要求：
1. 开头用场景/反问制造共鸣
2. 深入分析2-3个维度
3. 给出3-5条可操作建议
4. 用表格总结关键数据
5. 自然使用2-4个黑话词汇
6. 保持过来人口吻`;

return {
  model: 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 4096,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ],
  _owl_source_url: owl._owl_source_url
};

const response = $input.first().json;
const article = response.choices?.[0]?.message?.content || '';

const firstLine = article.split('\n').find(l => l.trim() && !l.startsWith('```')) || '';
const title = firstLine.replace(/^#+\s*/, '').substring(0, 100);

function guessSubreddit(c) {
  const lc = (c||'').toLowerCase();
  if (lc.includes('ap ')) return 'APExams';
  if (lc.includes('a-level')||lc.includes('alevel')) return 'ALevel';
  if (lc.includes('ib ')) return 'IBDiploma';
  if (lc.includes('sat')||lc.includes('act')) return 'SATPrep';
  if (lc.includes('bpho')||lc.includes('amc')||lc.includes('竞赛')||lc.includes('olympiad')) return 'Competitions';
  if (lc.includes('oxbridge')||lc.includes('牛剑')||lc.includes('牛津')||lc.includes('剑桥')) return 'Oxbridge';
  return 'AcademicDaily';
}

return {
  secret_key: 'nexus-hub-test-secret-2026',
  title: title,
  content: article,
  subredditName: guessSubreddit(article),
  authorRole: 'Newton'
};

const response = $input.first().json;
return {
  pipeline: 'Nexus Hub v1',
  status: 'published',
  post_id: response.id,
  subreddit: response.subredditName,
  author: response.authorRole,
  url: 'http://localhost:3000/r/' + response.subredditName + '/post/' + response.id,
  timestamp: new Date().toISOString()
};
